create or replace function public.cancel_attendance(   p_attendance_id uuid,   p_reason text,   p_actor_id uuid ) returns void language plpgsql security definer set search_path = public as $$ declare   v_log public.attendance_logs%rowtype;   v_actor public.staff_users%rowtype;   v_reason text := trim(coalesce(p_reason, '')); begin   if char_length(v_reason) < 2 then     raise exception '異쒖꽍 痍⑥냼 ?ъ쑀瑜??낅젰??二쇱꽭??';   end if;   v_actor := public.assert_staff_actor(p_actor_id, array['owner','admin']);   select * into v_log   from public.attendance_logs   where id = p_attendance_id   for update;   if not found or v_log.status <> 'checked_in' then     raise exception '痍⑥냼 媛?ν븳 異쒖꽍 湲곕줉???꾨떃?덈떎.';   end if;   if v_actor.organization_id <> v_log.organization_id then     raise exception '?ㅻⅨ 議곗쭅??異쒖꽍 湲곕줉? 痍⑥냼?????놁뒿?덈떎.';   end if;   update public.attendance_logs   set status = 'cancelled',       cancelled_by = p_actor_id,       cancelled_at = now(),       memo = v_reason   where id = p_attendance_id;   if v_log.member_pass_id is not null and coalesce(v_log.deducted_sessions, 0) > 0 then     update public.member_passes     set used_sessions = greatest(used_sessions - v_log.deducted_sessions, 0),         remaining_sessions = remaining_sessions + v_log.deducted_sessions,         status = case when status = 'used_up' then 'active' else status end,         updated_at = now()     where id = v_log.member_pass_id;   end if;   insert into public.audit_logs(     organization_id,     actor_id,     action,     entity_type,     entity_id,     before_data,     after_data   ) values (     v_log.organization_id,     p_actor_id,     'ATTENDANCE_CANCELLED',     'attendance_logs',     p_attendance_id,     to_jsonb(v_log),     jsonb_build_object('reason', v_reason, 'restored_sessions', v_log.deducted_sessions)   ); end; $$;
